import{_ as a,o as i,c as t,a2 as o}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"ADR-0001: Phase 01 Pi-hole Appliance Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/adrs/0001-phase-01-appliance-architecture.md","filePath":"sovereign-os/adrs/0001-phase-01-appliance-architecture.md"}'),r={name:"sovereign-os/adrs/0001-phase-01-appliance-architecture.md"};function n(s,e,l,d,c,h){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-0001-phase-01-pi-hole-appliance-architecture" tabindex="-1">ADR-0001: Phase 01 Pi-hole Appliance Architecture <a class="header-anchor" href="#adr-0001-phase-01-pi-hole-appliance-architecture" aria-label="Permalink to &quot;ADR-0001: Phase 01 Pi-hole Appliance Architecture&quot;">​</a></h1><p><strong>Status:</strong> Accepted<br><strong>Date:</strong> 2026-07-19<br><strong>Decision owner:</strong> Project creator<br><strong>Related plan:</strong> <a href="./../roadmap/01-preview-poc.html">Phase 01</a><br><strong>Related RFC:</strong> <a href="./../rfcs/0010-raspberry-pi-image-deployment.html">RFC-0010</a></p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The original Phase 01 preview combined a dashboard, AI orchestration, capability contracts, and Pi-hole integration. That scope required several platform decisions before producing a usable artifact.</p><p>The project instead needs an earlier proof that it can deliver a coherent home appliance: a user flashes one image, boots a Raspberry Pi, and receives an operational Pi-hole service without installing software.</p><p>The image also needs a route namespace that will remain compatible with future Sovereign interfaces. Pi-hole must therefore occupy <code>/dns/*</code>, leaving <code>/admin/*</code> and <code>/api/*</code> available to the future platform.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Phase 01 will deliver a flashable Raspberry Pi 5 image with:</p><ul><li>Raspberry Pi OS Lite 64-bit as the base operating system;</li><li>Docker Engine and Compose as the application deployment boundary;</li><li>the official Pi-hole ARM64 container pinned by immutable digest;</li><li>the Pi-hole container artifact embedded for offline first boot;</li><li>persistent Pi-hole data on the host;</li><li>a unique Pi-hole administrator credential generated on first boot;</li><li>Nginx as the proposed host reverse proxy, subject to RFC validation;</li><li>Pi-hole served externally under <code>/dns/admin/*</code> and <code>/dns/api/*</code>;</li><li>Avahi advertising the system as <code>sovereign.local</code>;</li><li>an idempotent first-boot systemd service.</li></ul><p>The Phase 01 image will not include the Sovereign dashboard, AI runtime, LLM, capability system, voice, Home Assistant, or a general plugin system.</p><p>Pi-hole DHCP will be disabled by default. Users must configure their router or devices to use the Pi&#39;s stable address as DNS.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Produces a small, understandable, demonstrable first milestone.</li><li>Validates image build, first boot, networking, persistence, and release mechanics early.</li><li>Pins Pi-hole independently of base-OS packages.</li><li>Provides a clean deployment pattern for later containerized services.</li><li>Preserves <code>/admin</code> and <code>/api</code> for Sovereign.</li><li>Allows container replacement without mixing Pi-hole files into the base OS.</li><li>Supports an offline first boot.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Adds Docker runtime, storage, networking, and maintenance overhead.</li><li>Requires explicit container artifact and base-OS supply-chain management.</li><li>Requires a reverse proxy to provide the <code>/dns</code> prefix.</li><li>Does not eliminate the user&#39;s router DNS configuration step.</li><li>Defers validation of the AI-native product concept.</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>Port 53 may conflict with a host resolver.</li><li>Pi-hole prefix behavior may regress across releases.</li><li>Persistent Pi-hole data may not be backward compatible after upgrades.</li><li>Container and host firewall rules may expose unintended services.</li><li>mDNS may fail across isolated networks or unsupported clients.</li><li>First-boot interruption could leave partial state without careful idempotency.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><h3 id="native-pi-hole-installation" tabindex="-1">Native Pi-hole installation <a class="header-anchor" href="#native-pi-hole-installation" aria-label="Permalink to &quot;Native Pi-hole installation&quot;">​</a></h3><p>Rejected for Phase 01 because unattended installation inside an image build is more coupled to chroot state, running services, network detection, and base-OS packages. It remains viable if container behavior becomes a blocker.</p><h3 id="ubuntu-server-base" tabindex="-1">Ubuntu Server base <a class="header-anchor" href="#ubuntu-server-base" aria-label="Permalink to &quot;Ubuntu Server base&quot;">​</a></h3><p>Rejected for Phase 01 in favor of Raspberry Pi OS Lite&#39;s smaller footprint and direct alignment with Raspberry Pi hardware and image tooling.</p><h3 id="dashboard-and-ai-in-the-first-image" tabindex="-1">Dashboard and AI in the first image <a class="header-anchor" href="#dashboard-and-ai-in-the-first-image" aria-label="Permalink to &quot;Dashboard and AI in the first image&quot;">​</a></h3><p>Deferred because they do not contribute to validating the image appliance foundation and would obscure failures behind multiple new systems.</p><h3 id="pi-hole-on-root-admin-and-api" tabindex="-1">Pi-hole on root <code>/admin</code> and <code>/api</code> <a class="header-anchor" href="#pi-hole-on-root-admin-and-api" aria-label="Permalink to &quot;Pi-hole on root `/admin` and `/api`&quot;">​</a></h3><p>Rejected because those paths are valuable future Sovereign namespaces. Pi-hole v6 supports a reverse-proxy prefix specifically for this purpose.</p><h2 id="validation-and-revisit-conditions" tabindex="-1">Validation and Revisit Conditions <a class="header-anchor" href="#validation-and-revisit-conditions" aria-label="Permalink to &quot;Validation and Revisit Conditions&quot;">​</a></h2><p>Revisit this decision if:</p><ul><li>Docker prevents reliable DNS or significantly complicates recovery;</li><li>Pi-hole cannot pass the required <code>/dns/*</code> regression tests;</li><li>the embedded OCI artifact makes image production impractical;</li><li>measured resource or storage overhead is unacceptable;</li><li>official Pi-hole distribution or licensing requirements conflict with embedding;</li><li>a native package path becomes clearly more reproducible and maintainable.</li></ul>',30)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
